function calculate() {
  const householdsTier1 = parseFloat(inputs.householdsTier1) || 0;
  const avgNetWorthTier1 = parseFloat(inputs.avgNetWorthTier1) || 0;
  const exemptionThreshold1 = parseFloat(inputs.exemptionThreshold1) || 0;
  const taxRate1 = parseFloat(inputs.taxRate1) / 100 || 0;

  const householdsTier2 = parseFloat(inputs.householdsTier2) || 0;
  const avgNetWorthTier2 = parseFloat(inputs.avgNetWorthTier2) || 0;
  const exemptionThreshold2 = parseFloat(inputs.exemptionThreshold2) || 0;
  const taxRate2 = parseFloat(inputs.taxRate2) / 100 || 0;

  const complianceRate = parseFloat(inputs.complianceRate) / 100 || 0;
  const adminCostRate = parseFloat(inputs.adminCostRate) / 100 || 0;

  // Ensure thresholds are positive and rates are within reasonable bounds
  const effectiveThreshold1 = Math.max(0, exemptionThreshold1);
  const effectiveThreshold2 = Math.max(0, exemptionThreshold2);
  const effectiveTaxRate1 = Math.min(Math.max(0, taxRate1), 1);
  const effectiveTaxRate2 = Math.min(Math.max(0, taxRate2), 1);
  const effectiveComplianceRate = Math.min(Math.max(0, complianceRate), 1);
  const effectiveAdminCostRate = Math.min(Math.max(0, adminCostRate), 1);

  // Calculate taxable wealth for Tier 1
  let taxableWealthTier1 = 0;
  if (householdsTier1 > 0 && avgNetWorthTier1 > effectiveThreshold1) {
    // Wealth between threshold 1 and threshold 2 (implicitly handled by average)
    // For simplicity, we assume avgNetWorthTier1 represents the average *taxable* wealth for the bracket if it's above threshold 1 but below threshold 2.
    // A more complex model would require wealth distribution within the bracket.
    // Here, we take the average net worth and subtract the threshold for each household in this tier.
    const netWealthAboveThreshold1 = Math.max(0, avgNetWorthTier1 - effectiveThreshold1);
    taxableWealthTier1 = netWealthAboveThreshold1 * householdsTier1;
  }

  // Calculate taxable wealth for Tier 2
  let taxableWealthTier2 = 0;
  if (householdsTier2 > 0 && avgNetWorthTier2 > effectiveThreshold2) {
    const netWealthAboveThreshold2 = Math.max(0, avgNetWorthTier2 - effectiveThreshold2);
    taxableWealthTier2 = netWealthAboveThreshold2 * householdsTier2;
  }

  // Calculate gross revenue
  const grossRevenueTier1 = taxableWealthTier1 * effectiveTaxRate1;
  const grossRevenueTier2 = taxableWealthTier2 * effectiveTaxRate2;
  const estimatedGrossRevenue = grossRevenueTier1 + grossRevenueTier2;

  // Adjust for compliance and administrative costs
  const revenueAfterCompliance = estimatedGrossRevenue * effectiveComplianceRate;
  const administrativeCosts = estimatedGrossRevenue * effectiveAdminCostRate;
  const estimatedNetRevenue = revenueAfterCompliance - administrativeCosts;

  return {
    taxableWealthTier1: taxableWealthTier1,
    taxableWealthTier2: taxableWealthTier2,
    estimatedGrossRevenue: estimatedGrossRevenue,
    estimatedNetRevenue: Math.max(0, estimatedNetRevenue) // Ensure net revenue is not negative
  };
}
